    // Constraints: nums[i] <= 10^5. We need a safety margin for searching the next required number.
    const MAX_VAL = 100000 + 20; 

    // 1. Sieve of Eratosthenes to pre-calculate primes up to MAX_VAL
    const isPrime = new Array(MAX_VAL + 1).fill(true);
    isPrime[0] = isPrime[1] = false;

    for (let p = 2; p * p <= MAX_VAL; p++) {
        if (isPrime[p]) {
            for (let i = p * p; i <= MAX_VAL; i += p)
                isPrime[i] = false;
        }
    }

    // Helper function to check primality, relying on the sieve for efficiency.
    // Since the search gap is very small, we rely on MAX_VAL covering all necessary checks.
    const checkPrime = (n) => {
        if (n > MAX_VAL) {
             // Should not happen based on problem constraints and prime density, 
             // but added defensively.
            if (n <= 1) return false;
            for (let i = 2; i * i <= n; i++) {
                if (n % i === 0) return false;
            }
            return true;
        }
        return isPrime[n];
    };

    let totalOperations = 0;

    for (let i = 0; i < nums.length; i++) {
        let currentNum = nums[i];
        let target;

        if (i % 2 === 0) {
            // Even index: Target must be Prime
            let k = currentNum;
            while (true) {
                if (checkPrime(k)) {
                    target = k;
                    break;
                }
                k++;
            }
        } else {
            // Odd index: Target must be Non-Prime (1 or Composite)
            let k = currentNum;
            while (true) {
                // k is non-prime if k=1 OR if k is composite (not prime and k > 1)
                const is_prime = checkPrime(k);
                const is_non_prime = (k === 1) || !is_prime;

                if (is_non_prime) {
                    target = k;
                    break;
                }
                k++;
            }
        }

        totalOperations += (target - currentNum);
    }

    return totalOperations;
}

