function solve(nums) {
    const MAX_VAL = 100000 + 20; // Safety margin

    // 1. Sieve of Eratosthenes
    const isPrime = new Array(MAX_VAL + 1).fill(true);
    isPrime[0] = isPrime[1] = false;
    for (let p = 2; p * p <= MAX_VAL; p++) {
        if (isPrime[p]) {
            for (let i = p * p; i <= MAX_VAL; i += p)
                isPrime[i] = false;
        }
    }

    // Helper function to check if a number is prime based on the sieve
    const checkPrime = (n) => {
        if (n > MAX_VAL) {
            // This should ideally not happen given constraints and density of primes, 
            // but if it does, we fall back to trial division.
            if (n <= 1) return false;
            for (let i = 2; i * i <= n; i++) {
                if (n % i === 0) return false;
            }
            return true;
        }
        return isPrime[n];
    };

    let totalOperations = 0;

    for (let i = 0; i < nums.length; i++) {
        let currentNum = nums[i];
        let target;

        if (i % 2 === 0) {
            // Even index: Must be Prime
            let k = currentNum;
            while (true) {
                if (checkPrime(k)) {
                    target = k;
                    break;
                }
                k++;
            }
        } else {
            // Odd index: Must be Non-Prime (1 or Composite)
            let k = currentNum;
            while (true) {
                // A number k is non-prime if it is 1 OR it is not prime (and > 1)
                const is_prime = checkPrime(k);
                const is_non_prime = (k === 1) || !is_prime;

                if (is_non_prime) {
                    target = k;
                    break;
                }
                k++;
            }
        }

        totalOperations += (target - currentNum);
    }

    return totalOperations;
}
